import React from 'react';
import { useQuery } from '@tanstack/react-query';
import { analyticsAPI } from '../services/api';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { Megaphone, Users, MessageSquare, TrendingUp, CheckCircle, XCircle, Clock, DollarSign } from 'lucide-react';
import { format } from 'date-fns';

const StatCard = ({ title, value, subtitle, icon: Icon, color, bg }) => (
  <div style={{
    background: 'white', borderRadius: '16px', padding: '24px',
    boxShadow: '0 1px 3px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9',
    display: 'flex', gap: '16px', alignItems: 'flex-start'
  }}>
    <div style={{
      width: '48px', height: '48px', borderRadius: '12px',
      background: bg, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0
    }}>
      <Icon size={22} color={color} />
    </div>
    <div>
      <div style={{ color: '#64748b', fontSize: '13px', fontWeight: 500, marginBottom: '4px' }}>{title}</div>
      <div style={{ fontSize: '28px', fontWeight: 700, color: '#0f172a', lineHeight: 1 }}>{value}</div>
      {subtitle && <div style={{ color: '#94a3b8', fontSize: '12px', marginTop: '4px' }}>{subtitle}</div>}
    </div>
  </div>
);

const CampaignStatusBadge = ({ status }) => {
  const styles = {
    completed: { bg: '#dcfce7', color: '#166534' },
    running: { bg: '#dbeafe', color: '#1e40af' },
    failed: { bg: '#fee2e2', color: '#991b1b' },
    draft: { bg: '#f1f5f9', color: '#475569' },
    scheduled: { bg: '#fef3c7', color: '#92400e' },
    paused: { bg: '#fce7f3', color: '#9d174d' },
  };
  const s = styles[status] || styles.draft;
  return (
    <span style={{
      padding: '3px 10px', borderRadius: '20px',
      background: s.bg, color: s.color, fontSize: '12px', fontWeight: 600
    }}>{status}</span>
  );
};

export default function DashboardPage() {
  const { data, isLoading } = useQuery({
    queryKey: ['dashboard'],
    queryFn: () => analyticsAPI.getDashboard(30).then(r => r.data.data),
    refetchInterval: 30000,
  });

  if (isLoading) return (
    <div style={{ padding: '40px', display: 'flex', alignItems: 'center', justifyContent: 'center', flex: 1 }}>
      <div style={{ color: '#64748b', fontSize: '16px' }}>Loading dashboard...</div>
    </div>
  );

  const d = data || {};
  const deliveryRate = d.messages?.delivery_rate || 0;
  const pieData = [
    { name: 'Delivered', value: parseInt(d.messages?.delivered || 0), color: '#22c55e' },
    { name: 'Failed', value: parseInt(d.messages?.failed || 0), color: '#ef4444' },
    { name: 'Pending', value: Math.max(0, parseInt(d.messages?.total_sent || 0) - parseInt(d.messages?.delivered || 0) - parseInt(d.messages?.failed || 0)), color: '#6366f1' },
  ];

  return (
    <div style={{ padding: '32px', background: '#f8fafc', minHeight: '100vh' }}>
      {/* Header */}
      <div style={{ marginBottom: '32px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 700, color: '#0f172a', marginBottom: '4px' }}>Dashboard</h1>
        <p style={{ color: '#64748b' }}>Overview of your SMS marketing activity (last 30 days)</p>
      </div>

      {/* Stat Cards */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '20px', marginBottom: '28px' }}>
        <StatCard title="Total Campaigns" value={d.campaigns?.total || 0}
          subtitle={`${d.campaigns?.running || 0} running`}
          icon={Megaphone} color="#6366f1" bg="#eef2ff" />
        <StatCard title="Total Contacts" value={parseInt(d.contacts?.total || 0).toLocaleString()}
          subtitle={`${d.contacts?.active || 0} active`}
          icon={Users} color="#22c55e" bg="#dcfce7" />
        <StatCard title="Messages Sent" value={parseInt(d.messages?.total_sent || 0).toLocaleString()}
          subtitle="Last 30 days"
          icon={MessageSquare} color="#3b82f6" bg="#dbeafe" />
        <StatCard title="Delivery Rate" value={`${deliveryRate}%`}
          subtitle={`${d.messages?.delivered || 0} delivered`}
          icon={TrendingUp} color="#f59e0b" bg="#fef3c7" />
        <StatCard title="Total Cost" value={`$${parseFloat(d.messages?.total_cost || 0).toFixed(4)}`}
          subtitle="SMS sending cost"
          icon={DollarSign} color="#8b5cf6" bg="#f3e8ff" />
        <StatCard title="Opt-Outs" value={d.opt_outs?.opt_outs || 0}
          subtitle="Last 30 days"
          icon={XCircle} color="#ef4444" bg="#fee2e2" />
      </div>

      {/* Charts Row */}
      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '20px', marginBottom: '28px' }}>
        {/* Daily Stats Chart */}
        <div style={{ background: 'white', borderRadius: '16px', padding: '24px', boxShadow: '0 1px 3px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' }}>
          <h3 style={{ fontSize: '16px', fontWeight: 600, color: '#0f172a', marginBottom: '20px' }}>Message Activity</h3>
          <ResponsiveContainer width="100%" height={220}>
            <AreaChart data={d.daily_stats || []}>
              <defs>
                <linearGradient id="sent" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#6366f1" stopOpacity={0.2}/>
                  <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                </linearGradient>
                <linearGradient id="delivered" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#22c55e" stopOpacity={0.2}/>
                  <stop offset="95%" stopColor="#22c55e" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
              <XAxis dataKey="date" tick={{ fontSize: 11, fill: '#94a3b8' }} />
              <YAxis tick={{ fontSize: 11, fill: '#94a3b8' }} />
              <Tooltip />
              <Area type="monotone" dataKey="sent" stroke="#6366f1" fill="url(#sent)" strokeWidth={2} name="Sent" />
              <Area type="monotone" dataKey="delivered" stroke="#22c55e" fill="url(#delivered)" strokeWidth={2} name="Delivered" />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        {/* Delivery Pie */}
        <div style={{ background: 'white', borderRadius: '16px', padding: '24px', boxShadow: '0 1px 3px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' }}>
          <h3 style={{ fontSize: '16px', fontWeight: 600, color: '#0f172a', marginBottom: '20px' }}>Delivery Status</h3>
          <ResponsiveContainer width="100%" height={160}>
            <PieChart>
              <Pie data={pieData} cx="50%" cy="50%" innerRadius={45} outerRadius={70} dataKey="value">
                {pieData.map((entry, i) => <Cell key={i} fill={entry.color} />)}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', marginTop: '12px' }}>
            {pieData.map(item => (
              <div key={item.name} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <div style={{ width: '10px', height: '10px', borderRadius: '50%', background: item.color }} />
                  <span style={{ fontSize: '13px', color: '#64748b' }}>{item.name}</span>
                </div>
                <span style={{ fontSize: '13px', fontWeight: 600, color: '#0f172a' }}>{item.value.toLocaleString()}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Recent Campaigns */}
      <div style={{ background: 'white', borderRadius: '16px', padding: '24px', boxShadow: '0 1px 3px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' }}>
        <h3 style={{ fontSize: '16px', fontWeight: 600, color: '#0f172a', marginBottom: '20px' }}>Recent Campaigns</h3>
        {(!d.recent_campaigns || d.recent_campaigns.length === 0) ? (
          <div style={{ textAlign: 'center', padding: '40px', color: '#94a3b8' }}>No campaigns yet. Create your first campaign!</div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                {['Campaign', 'Status', 'Sent', 'Delivered', 'Failed', 'Created'].map(h => (
                  <th key={h} style={{ textAlign: 'left', padding: '8px 12px', color: '#94a3b8', fontSize: '12px', fontWeight: 600, borderBottom: '1px solid #f1f5f9' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {d.recent_campaigns.map(c => (
                <tr key={c.id} style={{ borderBottom: '1px solid #f8fafc' }}>
                  <td style={{ padding: '12px', fontSize: '14px', fontWeight: 500, color: '#0f172a' }}>{c.name}</td>
                  <td style={{ padding: '12px' }}><CampaignStatusBadge status={c.status} /></td>
                  <td style={{ padding: '12px', fontSize: '14px', color: '#64748b' }}>{c.sent_count || 0}</td>
                  <td style={{ padding: '12px', fontSize: '14px', color: '#22c55e', fontWeight: 500 }}>{c.delivered_count || 0}</td>
                  <td style={{ padding: '12px', fontSize: '14px', color: '#ef4444', fontWeight: 500 }}>{c.failed_count || 0}</td>
                  <td style={{ padding: '12px', fontSize: '13px', color: '#94a3b8' }}>
                    {c.created_at ? format(new Date(c.created_at), 'MMM dd, yyyy') : '-'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
